BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?verificationName ?activity ?activityName WHERE {
  ?verification rdf:type vocab:verification .
  ?verification vocab:NamedElement_name ?verificationName .
  FILTER(CONTAINS(LCASE(STR(?verificationName)), LCASE("Post%20Segment%20Exchange")))
  OPTIONAL { ?verification vocab:NamedElement_name ?verificationName . }
  OPTIONAL { ?verification vocab:include ?activity . }
  OPTIONAL { ?activity vocab:NamedElement_name ?activityName . }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?ver ?verName ?activity ?activityName ?rel WHERE {
  ?ver vocab:NamedElement_name ?verName .
  FILTER(CONTAINS(LCASE(STR(?verName)), LCASE("verification")))
  FILTER(CONTAINS(LCASE(STR(?verName)), LCASE("Post%20Segment%20Exchange")) || CONTAINS(LCASE(STR(?verName)), LCASE("Post Segment Exchange")))

  {
    ?ver vocab:include ?activity .
    BIND(vocab:include AS ?rel)
  }
  UNION
  {
    ?ver vocab:verify ?activity .
    BIND(vocab:verify AS ?rel)
  }
  UNION
  {
    ?ver vocab:satisfy ?activity .
    BIND(vocab:satisfy AS ?rel)
  }
  UNION
  {
    ?ver vocab:allocate ?activity .
    BIND(vocab:allocate AS ?rel)
  }

  OPTIONAL { ?activity vocab:NamedElement_name ?activityName . }
}
LIMIT 25
